 1	import React, { useState } from 'react';
 2	import {
 3	  Bullseye,
 4	  Button,
 5	  EmptyState,
 6	  EmptyStateBody,
 7	  Flex,
 8	  FlexItem,
 9	} from '@patternfly/react-core';
10	import { useTranslation } from 'react-i18next';
11	import { TraceQueryPanelWrapper } from '../../components/PersesWrapper';
12	import { ScatterChart } from '@perses-dev/panels-plugin';
13	import { ExpandIcon, CompressIcon } from '@patternfly/react-icons';
14	import { useRefWidth } from '../../components/console/utils/ref-width-hook';
15	import { useNavigate } from 'react-router-dom-v5-compat';
16	import { linkToTraceDetailPage } from '../../links';
17	
18	export function ScatterPlot() {
19	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
20	  const navigate = useNavigate();
21	  const [isVisible, setVisible] = useState(true);
22	  const [ref, width] = useRefWidth();
23	
24	  const clickHandler = (data: { traceId: string }) => {
25	    navigate(linkToTraceDetailPage(data.traceId));
26	  };
27	
28	  const noResults = (
29	    <Bullseye>
30	      <EmptyState>
31	        <EmptyStateBody>{t('No datapoints found.')}</EmptyStateBody>
32	      </EmptyState>
33	    </Bullseye>
34	  );
35	
36	  return (
37	    <div>
38	      <Flex>
39	        <FlexItem align={{ default: 'alignRight' }}>
40	          <Button
41	            variant="link"
42	            className="pf-m-link pf-v5-u-text-align-right"
43	            onClick={() => setVisible(!isVisible)}
44	          >
45	            {isVisible ? (
46	              <>
47	                <CompressIcon /> {t('Hide graph')}
48	              </>
49	            ) : (
50	              <>
51	                <ExpandIcon /> {t('Show graph')}
52	              </>
53	            )}
54	          </Button>
55	        </FlexItem>
56	      </Flex>
57	
58	      {isVisible && (
59	        <div
60	          ref={ref}
61	          style={{
62	            height: '200px',
63	            flexShrink: 0,
64	            border: 'var(--pf-global--BorderWidth--sm) solid var(--pf-global--BorderColor--100)',
65	          }}
66	        >
67	          <TraceQueryPanelWrapper noResults={noResults}>
68	            <ScatterChart.PanelComponent
69	              contentDimensions={{
70	                width,
71	                height: 200,
72	              }}
73	              spec={{}}
74	              onClick={clickHandler}
75	            />
76	          </TraceQueryPanelWrapper>
77	        </div>
78	      )}
79	    </div>
80	  );
81	}

